// application.yml:
// server.shutdown: graceful
// spring.lifecycle.timeout-per-shutdown-phase: 50s
// management.health.probes.enabled: true

// Deployment container spec:
// lifecycle:
//   preStop:
//     exec:
//       command: ['/bin/sh', '-c', 'sleep 5']
// terminationGracePeriodSeconds: 60

// POD TERMINATION SEQUENCE:
// T=0:   k8s sends SIGTERM + removes pod from Service endpoints
// T=0:   preStop hook starts (sleep 5s)
// T=5s:  preStop completes; Spring Boot shutdown begins
// T=5s:  Spring Boot: sets readiness to 'not ready' (readinessProbe fails)
// T=5s:  Spring Boot: finishes in-flight requests (up to 50s)
// T=55s: Spring Boot JVM exits (all requests done)
// T=60s: terminationGracePeriodSeconds deadline — k8s sends SIGKILL if still running

import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class GracefulShutdownTest {
    @Autowired WebTestClient wc;
    @Test void readiness_before_shutdown() {
        wc.get().uri('/actuator/health/readiness')
          .exchange().expectStatus().is2xxSuccessful();
    }
}

