import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.TestPropertySource;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.springframework.stereotype.Service;

@Service
class AppConfig {
    @Value('${spring.datasource.url:jdbc:h2:mem:testdb}')
    private String dbUrl;

    @Value('${spring.datasource.password:changeme}')
    private String dbPassword;

    public String getDbUrl() { return dbUrl; }
    // Never expose password via getter in real code!
    boolean hasPassword() { return dbPassword != null && !dbPassword.isEmpty(); }
}

@SpringBootTest
@TestPropertySource(properties = {
    'spring.datasource.url=jdbc:h2:mem:testdb',
    'spring.datasource.password=testpass'
})
class ConfigMapValueTest {
    @Autowired AppConfig config;

    @Test void dbUrl_injected_correctly() {
        assertNotNull(config.getDbUrl());
        assertTrue(config.getDbUrl().startsWith('jdbc:'));
    }

    @Test void password_injected() {
        assertTrue(config.hasPassword());
    }

    // In k8s: Secret env var SPRING_DATASOURCE_PASSWORD → spring.datasource.password
    // k8s env var name → Spring property: SPRING_DATASOURCE_PASSWORD → spring.datasource.password
    // Spring Boot converts ALL_CAPS_WITH_UNDERSCORES to dots.and.lower.case
}

