// k8s/payment-configmap.yml:
// data.application.yml: spring.datasource.url, log levels, pool size

// k8s/payment-secrets.yml:
// data: db_password, redis_password, visa_api_key (base64)

// k8s/deployment.yml:
// volumeMounts: /app/config → payment-config ConfigMap
// env: SPRING_DATASOURCE_PASSWORD from payment-secrets.db_password

@Service
class RzpConfigService {
    @Value('${spring.datasource.url:jdbc:h2:mem:testdb}') String dbUrl;
    @Value('${payment.visa.api-key:test-key-12345}') String visaKey;
    String getDbUrl() { return dbUrl; }
    boolean hasVisaKey() { return visaKey != null && visaKey.length() > 5; }
}

@SpringBootTest
@TestPropertySource(properties = {
    'spring.datasource.url=jdbc:h2:mem:payments',
    'payment.visa.api-key=rzp_test_abc123'
})
class RzpConfigTest {
    @Autowired RzpConfigService svc;
    @Test void dbUrl_configured(){
        assertEquals('jdbc:h2:mem:payments', svc.getDbUrl());
    }
    @Test void visaKey_hasValue(){
        assertTrue(svc.hasVisaKey());
    }
}

// STARTUP PROBE:
// startupProbe: 'has the app finished starting?'
// Once it passes: k8s switches to readiness + liveness probes
// This prevents liveness from killing a slow-but-healthy starting app

// WITHOUT startupProbe (problematic):
//   livenessProbe.initialDelaySeconds: 90  ← long delay
//   But: if probe period is 30s and app takes 85s: misses first 3 probes
//   If app is actually dead (not just slow): liveness doesn't catch it for 90s!

// WITH startupProbe (correct):
//   startupProbe:
//     httpGet: { path: /actuator/health/liveness, port: 8080 }
//     failureThreshold: 30   # allow up to 30 failures
//     periodSeconds: 10      # check every 10s → max startup = 300s
//   livenessProbe:
//     httpGet: { path: /actuator/health/liveness, port: 8080 }
//     initialDelaySeconds: 0   # no delay needed (startupProbe handles it)
//     periodSeconds: 30

// STARTUP PROBE vs LONG initialDelaySeconds:
// initialDelaySeconds: 90 means liveness doesn't check for 90s
//   → if app crashes at T=91s: liveness detects, restarts pod → OK
//   → if app is slow but fails at T=95s: still OK but close
// startupProbe: checks every 10s during startup
//   → if app crashes during startup at any point: startupProbe detects quickly
//   → once startupProbe passes: liveness immediately starts monitoring
//   → more precise: Flyway completes at 45s? startupProbe passes at 50s
//   → no waiting for arbitrary initialDelaySeconds=90

import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class StartupProbeTest {
    @Autowired WebTestClient wc;
    @Test void liveness_available_after_startup() {
        wc.get().uri('/actuator/health/liveness')
          .exchange().expectStatus().is2xxSuccessful();
    }
}

import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.TestPropertySource;
import org.springframework.test.web.reactive.server.WebTestClient;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.springframework.stereotype.Service;

@Service
class PaymentConfigValues {
    @Value('${spring.datasource.url:jdbc:h2:mem:payments}') String dbUrl;
    @Value('${management.tracing.sampling.probability:1.0}') double samplingRate;
    @Value('${logging.level.com.razorpay:INFO}') String logLevel;
    public String getDbUrl() { return dbUrl; }
    public double getSamplingRate() { return samplingRate; }
    public String getLogLevel() { return logLevel; }
}

// application.yml for test (simulates ConfigMap values):
// server.shutdown: graceful
// spring.lifecycle.timeout-per-shutdown-phase: 50s
// management.health.probes.enabled: true

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
@TestPropertySource(properties = {
    'spring.datasource.url=jdbc:h2:mem:payments',
    'management.tracing.sampling.probability=0.1',
    'logging.level.com.razorpay=INFO'
})
class M21T3SynthesisTest {
    @Autowired WebTestClient wc;
    @Autowired PaymentConfigValues cfg;

    @Test void configValues_injected(){
        assertEquals('jdbc:h2:mem:payments', cfg.getDbUrl());
        assertEquals(0.1, cfg.getSamplingRate(), 0.001);
        assertEquals('INFO', cfg.getLogLevel());
    }
    @Test void readiness_available(){
        wc.get().uri('/actuator/health/readiness').exchange().expectStatus().is2xxSuccessful();
    }
    @Test void liveness_returnsUp(){
        wc.get().uri('/actuator/health/liveness').exchange().expectStatus().is2xxSuccessful()
          .expectBody().jsonPath('$.status').isEqualTo('UP');
    }
}
